path='logs/sweeps/action_sweep.json'
if os.path.exists(path):
    data=json.load(open(path))
    if isinstance(data, dict):
        items=[]
        for task, recs in data.items():
            if isinstance(recs, dict):
                recs=list(recs.values())
            for r in recs:
                rr=dict(r); rr.setdefault('task', task); items.append(rr)
    else:
        items=data
    bars={'h1hand-sit_simple-v0':750,'h1hand-pole-v0':700,'h1hand-door-v0':600,'h1hand-push-v0':700,'h1hand-walk-v0':700,'h1hand-stand-v0':800}
    for task in bars:
        recs=[r for r in items if r.get('task')==task or r.get('task_id')==task]
        def mean_reward(r):
            if 'mean_reward' in r: return float(r['mean_reward'])
            if 'rewards' in r: return sum(r['rewards'])/len(r['rewards'])
            if 'reward' in r: return float(r['reward'])
            return -1e9
        recs=sorted(recs,key=mean_reward,reverse=True)[:8]
        print('TASK',task,'n',len([r for r in items if r.get('task')==task or r.get('task_id')==task]),'bar',bars[task])
        for r in recs:
            kind=r.get('kind') or r.get('action') or r.get('name') or r.get('policy')
            rewards=r.get('rewards') or r.get('episode_rewards')
            succ=sum(x>=bars[task] for x in rewards) if rewards else r.get('successes', r.get('success'))
            print(' ',kind,'mean',round(mean_reward(r),1),'succ',succ,'rewards', [round(x,1) for x in rewards[:10]] if rewards else '')
